UPDATE public.questions SET
  stimulus_text = 'A scientist is researching the use of external stimuli to reduce the itching sensation caused by an allergic histamine response.  She finds that while harmless applications of vibration or warming can provide a temporary distraction, such innocuous stimuli actually offer less relief than a stimulus that seems less benign, like a mild electric shock.  Which of the following is the most likely reason why the scientist uses the word "innocuous" in this context?',
